def validate_proof_map(claims: list, evidence_pack: dict) -> dict:
    """Validate claims are grounded in evidence"""
    issues = []
    grounded = 0

    for claim in claims:
        claim_text = claim.get("text", "")
        evidence_ref = claim.get("evidence_ref", None)

        if evidence_ref and evidence_ref in evidence_pack:
            grounded += 1
        else:
            issues.append(f"Ungrounded claim: '{claim_text[:50]}...' - soften language")

    return {
        "passed": len(issues) == 0,
        "grounded_count": grounded,
        "total_claims": len(claims),
        "grounded_pct": round(grounded / len(claims) * 100, 1) if claims else 0,
        "issues": issues
    }

def validate_slippery_slope(sections: list) -> dict: """Check for momentum-maintaining elements""" bucket_brigades = [ "here's the thing", "but wait", "and that's when", "now here's where", "so what does this mean", "but there's more", "here's what happened" ]
issues = [] sections_with_bridges = 0
for i, section in enumerate(sections): text = section.get("text", "").lower() has_bridge = any(bb in text for bb in bucket_brigades)
if has_bridge: sections_with_bridges += 1 elif i < len(sections) - 1: # Not the last section issues.append(f"Section {i+1} missing bucket brigade")
return { "passed": len(issues) <= 2, # Allow some flexibility "sections_with_bridges": sections_with_bridges, "total_sections": len(sections), "issues": issues }

def validate_kitchen_table_test(text: str) -> dict:
    """Check for overly marketing-speak language"""
    red_flags = [
        "breakthrough", "revolutionary", "game-changer", "unlock your",
        "life-changing", "transform your life", "secret weapon",
        "the one thing", "jaw-dropping", "mind-blowing", "incredible results",
        "limited time", "act now", "don't miss out", "hurry"
    ]

    issues = []
    text_lower = text.lower()

    for flag in red_flags:
        if flag in text_lower:
            count = text_lower.count(flag)
            issues.append(f"Marketing speak detected: '{flag}' ({count}x)")

    return {
        "passed": len(issues) <= 2,  # Some flexibility
        "issues_count": len(issues),
        "issues": issues,
        "recommendation": "Rewrite flagged phrases in conversational language" if issues else "Passes Kitchen Table Test"
    }
